/// An abstract heap type.
struct AbstractHeapType;

/// An abstract heap type.
struct AbstractHeapType;

struct FixupContext;

struct FixupContext;

/// A heap type.
struct HeapType;

/// Part of the function references proposal.
struct HeapType;

struct Precedence;

struct Precedence;

/// A reference type.
///
/// The reference types proposal first introduced `externref` and
/// `funcref`.
///
/// The function references proposal introduced typed function
/// references.
///
/// The GC proposal introduces heap types: any, eq, i31, struct, array,
/// nofunc, noextern, none.
struct RefType;

/// A reference type.
///
/// This is largely part of the function references proposal for WebAssembly but
/// additionally is used by the `funcref` and `externref` types. The full
/// generality of this type is only exercised with function-references.
struct RefType;

/// Indices for use with [`Termios::special_codes`].
struct SpecialCodeIndex;

/// Values per occurrence for an argument
struct ValueRange;

/// A byte slice descriptor for FFI (pointer + length).
struct HtpSlice {
  /// Pointer to the data.
  const uint8_t *ptr;
  /// Length of the data.
  uintptr_t len;
};

/// Parse result returned by `htp_at_parse`.
struct HtpAtParseResult {
  /// Parsed command ID.
  uint32_t id;
  /// Operation type: 0=Set, 1=Query, 2=Response.
  int32_t op;
  /// Offset of command name within the input buffer.
  uintptr_t name_offset;
  /// Length of command name.
  uintptr_t name_len;
  /// Number of parameters (max 8).
  uintptr_t param_count;
  /// Offsets of each parameter within the input buffer.
  uintptr_t param_offsets[8];
  /// Lengths of each parameter.
  uintptr_t param_lens[8];
};













































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































extern "C" {

/// Encodes an AT command string into the output buffer.
///
/// # Safety
/// All pointers must be valid for their respective lengths.

int32_t htp_at_encode(const uint8_t *name_ptr,
                      uintptr_t name_len,
                      uint32_t id,
                      int32_t op,
                      const HtpSlice *params_ptr,
                      uintptr_t params_count,
                      uint8_t *out_ptr,
                      uintptr_t out_cap,
                      uintptr_t *out_len);

/// Parses an AT command from a byte buffer.
///
/// On success, populates the `HtpAtParseResult` struct with offsets into the input buffer.
///
/// # Safety
/// All pointers must be valid.
 int32_t htp_at_parse(const uint8_t *input_ptr, uintptr_t input_len, HtpAtParseResult *result);

/// Frames payload bytes into a SysEx message.
///
/// # Safety
/// All pointers must be valid for their respective lengths.

int32_t htp_sysex_frame(const uint8_t *payload_ptr,
                        uintptr_t payload_len,
                        uint8_t *out_ptr,
                        uintptr_t out_cap,
                        uintptr_t *out_len);

/// Extracts payload from a SysEx message.
///
/// # Safety
/// All pointers must be valid.

int32_t htp_sysex_unframe(const uint8_t *data_ptr,
                          uintptr_t data_len,
                          uintptr_t *out_offset,
                          uintptr_t *out_len);

/// Converts SysEx bytes to USB MIDI 4-byte packets.
///
/// # Safety
/// All pointers must be valid for their respective lengths.

int32_t htp_usb_packetize(const uint8_t *sysex_ptr,
                          uintptr_t sysex_len,
                          uint8_t (*out_ptr)[4],
                          uintptr_t out_cap,
                          uintptr_t *out_count);

/// Reassembles SysEx bytes from USB MIDI 4-byte packets.
///
/// # Safety
/// All pointers must be valid for their respective lengths.

int32_t htp_usb_depacketize(const uint8_t (*packets_ptr)[4],
                            uintptr_t packet_count,
                            uint8_t *out_ptr,
                            uintptr_t out_cap,
                            uintptr_t *out_len);

/// Full pipeline: encode AT command → SysEx → USB MIDI packets.
///
/// # Safety
/// All pointers must be valid for their respective lengths.

int32_t htp_encode_to_packets(const uint8_t *name_ptr,
                              uintptr_t name_len,
                              uint32_t id,
                              int32_t op,
                              const HtpSlice *params_ptr,
                              uintptr_t params_count,
                              uint8_t *at_buf_ptr,
                              uintptr_t at_buf_cap,
                              uint8_t *sysex_buf_ptr,
                              uintptr_t sysex_buf_cap,
                              uint8_t (*packets_out_ptr)[4],
                              uintptr_t packets_out_cap,
                              uintptr_t *packets_out_count);

}  // extern "C"
